let streams = 0;
let pps = 0;

const artistData = [
    { id: '1300saint', name: '1300saint', cost: 15, pps: 1, rank: 8, lastRank:8, img: 'data:image/jpeg;base64,' }, 
    { id: 'ezcodylee', name: 'ezcodylee', cost: 100, pps: 5, rank: 7, lastRank: 7, img: 'data:image/jpeg;base64,' },
    { id: 'bleood', name: 'bleood', cost: 500, pps: 15, rank: 6, lastRank: 6, img: 'data:image/jpeg;base64,' },
    { id: 'prettifun', name: 'prettifun', cost: 1200, pps: 40, rank: 5, lastRank: 5, img: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ8mE984MIl1dyT4brBHb1mzBhQlQGSg27nDg&s' },
    { id: 'lucybedroque', name: 'lucybedroque', cost: 5000, pps: 120, rank: 4, lastRank: 4, img: 'data:image/jpeg;base64,' },
    { id: 'slayr', name: 'slayr', cost: 15000, pps: 450, rank: 3, lastRank: 3, img: 'data:image/jpeg;base64,' },
    { id: 'osomason', name: 'osamason', cost: 50000, pps: 1200, rank: 2, lastRank: 2, img: 'data:image/jpeg;base64,' },
    { id: 'nettspend', name: 'nettspend', cost: 150000, pps: 5000, rank: 1, lastRank: 1, img: 'data:image/jpeg;base64,' }
    
];

const ownedArtists = {};
artistData.forEach(a => ownedArtists[a.id] = 0);

// Initialize Shop (Build DOM structure once)
function initShop() {
    const shop = document.getElementById('shop-items');
    shop.innerHTML = '';
    
    artistData.forEach(artist => {
        const card = document.createElement('div');
        card.id = `shop-${artist.id}`;
        card.className = 'upgrade locked';
        card.onclick = () => buyArtist(artist.id);
        
        card.innerHTML = `
            <img src="${artist.img}" class="artist-img">
            <div class="upg-info">
                <span class="name">${artist.name}</span>
                <span class="cost" id="cost-${artist.id}">Plays: ${Math.floor(artist.cost)}</span>
            </div>
            <div class="count" id="count-${artist.id}">0</div>
        `;
        shop.appendChild(card);
    });
    updateShopStates(); // Set initial lock/unlock visual states
}

// Dynamically update visual lock state and item text without destroying the DOM elements
function updateShopStates() {
    artistData.forEach(artist => {
        const card = document.getElementById(`shop-${artist.id}`);
        const costEl = document.getElementById(`cost-${artist.id}`);
        const countEl = document.getElementById(`count-${artist.id}`);
        
        if (!card || !costEl || !countEl) return;

        // Update Text
        costEl.innerText = `Plays: ${Math.floor(artist.cost).toLocaleString()}`;
        countEl.innerText = ownedArtists[artist.id];

        // Check Lock Status
        const isLocked = streams < artist.cost && ownedArtists[artist.id] === 0;
        if (isLocked) {
            card.classList.add('locked');
        } else {
            card.classList.remove('locked');
        }
    });
}

function buyArtist(id) {
    const data = artistData.find(a => a.id === id);
    if (streams >= data.cost) {
        streams -= data.cost;
        ownedArtists[id]++;
        pps += data.pps;
        data.cost *= 1.15; // Price increases
        
        updateLog(`Signed ${data.name}!`);
        updateShopStates();
        updateUI();
    }
}

function updateUI() {
    // FIXED: changed "plays" to "streams"
    document.getElementById('play-count').innerText = Math.floor(streams).toLocaleString();
    document.getElementById('pps-count').innerText = pps.toLocaleString();
}

function updateLog(msg) {
    const log = document.getElementById('console-log');
    log.innerHTML = `> ${msg}<br>` + log.innerHTML;
}

document.getElementById('main-clicker').onclick = () => {
    streams += 1;
    updateUI();
    updateShopStates(); // Checks if clicking makes things available
};

setInterval(() => {
    streams += pps;
    updateUI();
    updateShopStates(); // Checks passive income eligibility
}, 1000);

// Run the initialization on page load
initShop();
updateUI();
setInterval(updateCharts, 5000);
